// Calculate date ranges
const now = new Date();

// Recent period: last 7 days
const recentEnd = new Date(now);
recentEnd.setDate(recentEnd.getDate() - 3); // GSC data has 3-day delay
const recentStart = new Date(recentEnd);
recentStart.setDate(recentStart.getDate() - 7);

// Previous period: 28 days before that
const prevEnd = new Date(recentStart);
prevEnd.setDate(prevEnd.getDate() - 1);
const prevStart = new Date(prevEnd);
prevStart.setDate(prevStart.getDate() - 28);

const fmt = (d) => d.toISOString().split('T')[0];

return [{
  json: {
    recent_start: fmt(recentStart),
    recent_end: fmt(recentEnd),
    previous_start: fmt(prevStart),
    previous_end: fmt(prevEnd)
  }
}];

// Compare recent vs previous performance per page
const recentData = $('Fetch GSC Recent 7 Days').first().json;
const prevData = $('Fetch GSC Previous 28 Days').first().json;

const recentRows = recentData.rows || [];
const prevRows = prevData.rows || [];

// Build lookup from previous period (normalize to weekly average)
const prevMap = {};
for (const row of prevRows) {
  const page = row.keys[0];
  prevMap[page] = {
    clicks: row.clicks / 4,       // 28 days → weekly avg
    impressions: row.impressions / 4,
    ctr: row.ctr,
    position: row.position
  };
}

const results = [];

for (const row of recentRows) {
  const page = row.keys[0];
  const prev = prevMap[page];

  if (!prev) continue; // New page, skip
  if (prev.clicks < 2) continue; // Too little traffic to matter

  const clickChange = row.clicks - prev.clicks;
  const clickChangePct = prev.clicks > 0 ? parseFloat(((clickChange / prev.clicks) * 100).toFixed(1)) : 0;
  const impressionChange = row.impressions - prev.impressions;
  const impressionChangePct = prev.impressions > 0 ? parseFloat(((impressionChange / prev.impressions) * 100).toFixed(1)) : 0;
  const positionChange = parseFloat((row.position - prev.position).toFixed(1)); // positive = worse

  // Determine decay severity
  let signal = 'STABLE';
  let severity = 'ok';

  if (clickChangePct <= -50 || (positionChange >= 5 && clickChangePct <= -30)) {
    signal = 'CRITICAL_DECAY';
    severity = 'critical';
  } else if (clickChangePct <= -30 || positionChange >= 3) {
    signal = 'DECAYING';
    severity = 'warning';
  } else if (clickChangePct <= -15 || positionChange >= 1.5) {
    signal = 'EARLY_DECAY';
    severity = 'watch';
  } else if (clickChangePct >= 20) {
    signal = 'GROWING';
    severity = 'good';
  }

  // Clean page path
  let pagePath = page;
  try {
    pagePath = new URL(page).pathname;
  } catch(e) {}

  results.push({
    json: {
      page_url: page,
      page_path: pagePath,

      clicks_now: row.clicks,
      clicks_before: parseFloat(prev.clicks.toFixed(1)),
      click_change: clickChange,
      click_change_pct: clickChangePct,

      impressions_now: row.impressions,
      impressions_before: parseFloat(prev.impressions.toFixed(1)),
      impression_change_pct: impressionChangePct,

      position_now: parseFloat(row.position.toFixed(1)),
      position_before: parseFloat(prev.position.toFixed(1)),
      position_change: positionChange,

      ctr_now: parseFloat((row.ctr * 100).toFixed(2)),
      ctr_before: parseFloat((prev.ctr * 100).toFixed(2)),

      signal: signal,
      severity: severity,

      date: new Date().toISOString().split('T')[0]
    }
  });
}

// Sort by worst decay first
results.sort((a, b) => a.json.click_change_pct - b.json.click_change_pct);

return results;

// Build the weekly decay report
const allPages = $('Compare Periods and Detect Decay').all().map(i => i.json);
const decaying = $input.all().map(i => i.json);

const critical = decaying.filter(p => p.severity === 'critical');
const warning = decaying.filter(p => p.severity === 'warning');
const watch = decaying.filter(p => p.severity === 'watch');
const stable = allPages.filter(p => p.severity === 'ok');
const growing = allPages.filter(p => p.severity === 'good');

const today = new Date().toISOString().split('T')[0];

// Total clicks lost
const totalClicksLost = decaying
  .filter(p => p.click_change < 0)
  .reduce((sum, p) => sum + Math.abs(p.click_change), 0);

let report = `*CONTENT DECAY REPORT — ${today}*\n`;
report += `Pages analyzed: ${allPages.length}\n\n`;

report += `Critical decay: ${critical.length}\n`;
report += `Decaying: ${warning.length}\n`;
report += `Early signs: ${watch.length}\n`;
report += `Stable: ${stable.length}\n`;
report += `Growing: ${growing.length}\n`;
report += `\n*Est. weekly clicks lost: ${Math.round(totalClicksLost)}*\n`;

if (critical.length > 0) {
  report += `\n\n*CRITICAL — Act now:*\n`;
  for (const p of critical.slice(0, 10)) {
    report += `• \`${p.page_path}\`\n`;
    report += `  Clicks: ${p.clicks_before} → ${p.clicks_now} (*${p.click_change_pct}%*)\n`;
    report += `  Position: ${p.position_before} → ${p.position_now} (${p.position_change > 0 ? '+' : ''}${p.position_change})\n`;
  }
}

if (warning.length > 0) {
  report += `\n*DECAYING — Update soon:*\n`;
  for (const p of warning.slice(0, 10)) {
    report += `• \`${p.page_path}\` — clicks ${p.click_change_pct}%, pos ${p.position_change > 0 ? '+' : ''}${p.position_change}\n`;
  }
}

if (watch.length > 0) {
  report += `\n*EARLY SIGNS — Keep watching:*\n`;
  for (const p of watch.slice(0, 5)) {
    report += `• \`${p.page_path}\` — clicks ${p.click_change_pct}%\n`;
  }
}

if (growing.length > 0) {
  report += `\n*TOP GROWING:*\n`;
  const topGrow = growing.sort((a, b) => b.click_change_pct - a.click_change_pct).slice(0, 3);
  for (const p of topGrow) {
    report += `• \`${p.page_path}\` — clicks +${p.click_change_pct}%\n`;
  }
}

return [{
  json: {
    report: report,
    total_pages: allPages.length,
    critical_count: critical.length,
    warning_count: warning.length,
    watch_count: watch.length,
    clicks_lost: Math.round(totalClicksLost),
    has_critical: critical.length > 0,
    critical_pages: critical.slice(0, 10),
    warning_pages: warning.slice(0, 10)
  }
}];

// Create individual tasks for critical decaying pages
const data = $input.first().json;
const tasks = [];

for (const page of data.critical_pages) {
  let action = '';

  if (page.position_change >= 5) {
    action = 'Major ranking drop. Check: lost backlinks, technical errors (404/redirect), or competitor new content. Run a backlink audit.';
  } else if (page.impression_change_pct <= -40) {
    action = 'Impressions tanking. Possible: Google algorithm change, keyword cannibalization, or index issues. Check Coverage report in GSC.';
  } else if (page.ctr_now < page.ctr_before * 0.7) {
    action = 'CTR dropped significantly. Update title tag and meta description. Check if SERP features (featured snippets, ads) pushed you down.';
  } else {
    action = 'Content likely outdated. Refresh with updated stats, new sections, better internal links. Check if search intent has shifted.';
  }

  tasks.push({
    json: {
      page_path: page.page_path,
      page_url: page.page_url,
      signal: page.signal,
      click_change_pct: page.click_change_pct,
      position_change: page.position_change,
      recommended_action: action,
      priority: 'HIGH',
      created: new Date().toISOString().split('T')[0]
    }
  });
}

return tasks;
